// ============================================================
// PARSE AI OUTPUT — Extrait et parse le JSON de la réponse IA
// Gère tous les cas : JSON brut, enveloppé dans ```json, texte mixte
// + Garde RH (plan != ENTERPRISE)
// + Injection LIMIT automatique si manquant
// ============================================================
const agentOutput = $input.first().json.output || '';
const planId = ($('Webhook2').item.json.body.planId || 'BASIC').toUpperCase();

const extractJSON = (text) => {
  if (!text || typeof text !== 'string') return null;
  if (typeof text === 'object') return text;

  let str = text.trim();
  str = str.replace(/^```(?:json)?\s*/im, '').replace(/\s*```\s*$/im, '').trim();

  const firstBrace = str.indexOf('{');
  const firstBracket = str.indexOf('[');
  let startIdx = -1;
  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) startIdx = firstBrace;
  else if (firstBracket !== -1) startIdx = firstBracket;

  if (startIdx > 0) str = str.slice(startIdx);

  const lastBrace = str.lastIndexOf('}');
  const lastBracket = str.lastIndexOf(']');
  const endIdx = Math.max(lastBrace, lastBracket);
  if (endIdx !== -1 && endIdx < str.length - 1) str = str.slice(0, endIdx + 1);

  try {
    return JSON.parse(str);
  } catch(e) {
    const repaired = str.replace(/,\s*([}\]])/g, '$1');
    try { return JSON.parse(repaired); } catch(e2) { return null; }
  }
};

// Tables RH interdites si plan != ENTERPRISE
const RH_TABLES = ['employees', 'departments', 'contracts', 'leaves', 'payroll_items', 'payroll_settings', 'primes'];

const containsRHTables = (sql) => {
  if (!sql) return false;
  const sqlLower = sql.toLowerCase();
  return RH_TABLES.some(table => sqlLower.includes(table));
};

// Injection LIMIT selon plan si absent
const injectLimit = (sql) => {
  if (!sql) return sql;
  const sqlLower = sql.toLowerCase();
  if (sqlLower.includes('limit ')) return sql;
  const limits = { BASIC: 10, PRO: 50 };
  const limit = limits[planId];
  if (!limit) return sql; // ENTERPRISE = sans limite
  return sql.trimEnd().replace(/;?\s*$/, '') + ` LIMIT ${limit}`;
};

const parsed = extractJSON(agentOutput);

if (!parsed || typeof parsed !== 'object') {
  return [{ json: {
    type: 'general_conversation',
    response: typeof agentOutput === 'string' && agentOutput.length > 0
      ? agentOutput
      : 'Je suis prêt à vous aider. Posez-moi une question sur vos données.',
    _parseError: true,
    _raw: String(agentOutput).slice(0, 200)
  }}];
}

// Garantit que 'type' existe toujours
if (!parsed.type) {
  if (parsed.sql) parsed.type = 'sql_query';
  else if (parsed.document_type) parsed.type = 'document_generation';
  else if (parsed.response) parsed.type = 'general_conversation';
  else parsed.type = 'general_conversation';
}

// Garantit que sql est bien un tableau si présent
if (parsed.sql && !Array.isArray(parsed.sql)) {
  parsed.sql = [parsed.sql];
}

// ═══ GARDE RH ═══
// Bloque l'accès aux tables RH si plan != ENTERPRISE
if ((parsed.type === 'sql_query' || parsed.type === 'document_generation') && parsed.sql) {
  const sqlString = parsed.sql.join(' ');
  if (planId !== 'ENTERPRISE' && containsRHTables(sqlString)) {
    return [{ json: {
      type: 'general_conversation',
      response: '🔒 **Accès refusé** — Les fonctionnalités RH (employés, paie, contrats) nécessitent le plan **ENTERPRISE**. Contactez votre administrateur pour mettre à niveau votre abonnement.',
      _blocked: 'rh_access',
      _plan: planId
    }}];
  }
}

// ═══ INJECTION LIMIT AUTOMATIQUE ═══
// Protège contre les requêtes sans LIMIT sur plans BASIC/PRO
if (parsed.type === 'sql_query' && parsed.sql && planId !== 'ENTERPRISE') {
  parsed.sql = parsed.sql.map(injectLimit);
}

// ═══ CTE MERGER — Multi-SQL fusionné en une seule requête WITH ═══
// Si l'IA retourne plusieurs SQLs, on les fusionne en CTEs pour éviter
// les erreurs d'exécution (le nœud Postgres n'exécute que sql[0])
if ((parsed.type === 'sql_query' || parsed.type === 'document_generation') && Array.isArray(parsed.sql) && parsed.sql.length > 1) {
  const queries = parsed.sql.map(q => q.trim().replace(/;?\s*$/, ''));
  const firstClean = queries[0].toLowerCase().trim();
  if (!firstClean.startsWith('with ')) {
    const cteNames = ['_cte_a', '_cte_b', '_cte_c', '_cte_d'];
    const ctes = queries.slice(0, -1).map((q, i) => `${cteNames[i]} AS (\n  ${q}\n)`).join(',\n');
    parsed.sql = [`WITH ${ctes}\n${queries[queries.length - 1]}`];
  } else {
    parsed.sql = [queries[0]];
  }
}

return [{ json: parsed }];

// ============================================================
// ANALYZE DATA TYPE — Détecte et enrichit le format de réponse
// ============================================================
const allResults = $input.all();
const aiOutput = $('Parse AI Output').first().json;
const userQuestion = $('Webhook2').first().json.body.message;
const sessionId = $('Webhook2').first().json.body.sessionId;
const planId = ($('Webhook2').first().json.body.planId || 'BASIC').toUpperCase();

let requestedFormat = aiOutput.format || 'auto';
const chartConfig = aiOutput.chart_config || null;
const kpiConfig = aiOutput.kpi_config || null;
const tableConfig = aiOutput.table_config || null;
const title = aiOutput.title || '';
const description = aiOutput.description || '';

const rowCount = allResults.length;
if (rowCount === 0) {
  return [{ json: { formattedResponse: `Aucune donnée trouvée pour : "${userQuestion}".`, sessionId, format: 'empty', resultCount: 0, title, description } }];
}

const firstRow = allResults[0]?.json || {};
const columns = Object.keys(firstRow);

if (requestedFormat === 'auto') {
  const hasDate = columns.some(c => c.match(/date|jour|mois|semaine|period|month|week|day/i));
  const hasNumeric = columns.some(c => { const v = firstRow[c]; return typeof v === 'number' || (!isNaN(parseFloat(v)) && v !== null); });
  const isSingleValue = rowCount === 1 && columns.length === 1;
  const isKPI = rowCount === 1 && columns.length <= 6 && hasNumeric;
  if (isSingleValue) requestedFormat = 'stats';
  else if (isKPI) requestedFormat = 'stats';
  else if (hasDate && rowCount > 3) requestedFormat = 'chart';
  else if (columns.length === 2 && rowCount <= 10) requestedFormat = 'donut_chart';
  else if (rowCount <= 15 && columns.length <= 3) requestedFormat = 'bar_chart';
  else if (rowCount > 15 || columns.length > 4) requestedFormat = 'table';
  else requestedFormat = 'list';
}

const cleanRow = (row) => {
  const out = {};
  for (const [k, v] of Object.entries(row || {})) {
    if (v === null || v === undefined) { out[k] = null; continue; }
    if (typeof v === 'object' && !Array.isArray(v)) {
      out[k] = (v instanceof Date || v.toISOString) ? (v.toISOString ? v.toISOString().split('T')[0] : String(v)) : JSON.stringify(v);
    } else { out[k] = v; }
  }
  return out;
};

const rawData = allResults.map(item => cleanRow(item.json || {}));

// ═══ PREDICTION / TREND — Format passe-en-avant avec flag is_prediction ═══
const IS_PREDICTION = requestedFormat === 'prediction' || requestedFormat === 'trend';

let statsObj = null;
if (['stats','chart','bar_chart','histogram','donut_chart','multi_chart','prediction','trend'].includes(requestedFormat)) {
  const numCols = {};
  for (const row of rawData) {
    for (const [k, v] of Object.entries(row)) {
      const n = parseFloat(v);
      if (!isNaN(n) && v !== null) { if (!numCols[k]) numCols[k] = []; numCols[k].push(n); }
    }
  }
  if (Object.keys(numCols).length > 0) {
    statsObj = {};
    for (const [col, vals] of Object.entries(numCols)) {
      const sum = vals.reduce((a, b) => a + b, 0);
      statsObj[col] = { sum: Math.round(sum*100)/100, avg: Math.round((sum/vals.length)*100)/100, min: Math.min(...vals), max: Math.max(...vals), count: vals.length };
    }
  }
}

const metadata = { format: requestedFormat, title, description, stats: statsObj, chart_config: chartConfig, kpi_config: kpiConfig, table_config: tableConfig, userQuestion, query: $('Parse AI Output').first().json.sql?.[0] || '', resultCount: rowCount, columnCount: columns.length, columns, planId, is_prediction: IS_PREDICTION };

return rawData.map(row => ({ json: { ...row, _metadata: metadata } }));

// ============================================================
// FORMAT SQL RESULTS ENHANCED — Construit la réponse finale
// ============================================================
const allResults = $input.all();
const sessionId = $('Webhook2').first().json.body.sessionId;
if (!allResults.length) return [{ json: { formattedResponse: 'Aucune donnée trouvée.', format: 'empty', resultCount: 0, sessionId } }];
const metadata = allResults[0]?.json?._metadata || {};
const { format: formatType = 'list', title = '', description = '', stats, chart_config, kpi_config, table_config, resultCount, columns = [] } = metadata;
const rawData = allResults.map(item => { const { _metadata, ...rest } = item.json || {}; return rest; });
const fmt = (v) => { if (v === null || v === undefined) return '—'; const n = parseFloat(v); if (!isNaN(n)) return n.toLocaleString('fr-FR', { minimumFractionDigits: 0, maximumFractionDigits: 2 }); return String(v); };
const mdTable = (data) => { if (!data.length) return ''; const cols = Object.keys(data[0]); return ['| ' + cols.join(' | ') + ' |', '|' + cols.map(() => '---').join('|') + '|', ...data.map(r => '| ' + cols.map(c => fmt(r[c])).join(' | ') + ' |')].join('\n'); };

const CHART_FORMATS = ['chart','bar_chart','histogram','donut_chart','multi_chart','heatmap','advanced_chart'];
if (CHART_FORMATS.includes(formatType)) {
  return [{ json: { formattedResponse: [title ? `**${title}**` : '', description || ''].filter(Boolean).join('\n'), sessionId, format: formatType, resultCount, rawResults: rawData, metadata: { ...metadata, chart_config } } }];
}
// ═══ PREDICTION / TREND — Régression linéaire + prévision 3 périodes ═══
if (formatType === 'prediction' || formatType === 'trend') {
  const timeCol = columns.find(c => /date|jour|mois|semaine|period|month|week|year|annee|periode/i.test(c)) || columns[0];
  const valueCol = columns.find(c => c !== timeCol && rawData[0] && !isNaN(parseFloat(rawData[0][c])));
  let forecast = [];
  if (valueCol && rawData.length >= 3) {
    const n = rawData.length;
    const xs = rawData.map((_, i) => i);
    const ys = rawData.map(r => parseFloat(r[valueCol]) || 0);
    const sumX = xs.reduce((a, b) => a + b, 0);
    const sumY = ys.reduce((a, b) => a + b, 0);
    const sumXY = xs.reduce((s, x, i) => s + x * ys[i], 0);
    const sumX2 = xs.reduce((s, x) => s + x * x, 0);
    const denom = (n * sumX2 - sumX * sumX) || 1;
    const slope = (n * sumXY - sumX * sumY) / denom;
    const intercept = (sumY - slope * sumX) / n;
    for (let i = 1; i <= 3; i++) {
      forecast.push({ [timeCol]: `Prév. +${i}`, [valueCol]: Math.max(0, Math.round((intercept + slope * (n - 1 + i)) * 100) / 100), _forecast: true });
    }
  }
  const chartData = [...rawData, ...forecast];
  const forecastChart = chart_config || { type: 'composed', xAxis: timeCol, series: [{ key: valueCol || columns[1] || columns[0], type: 'area', color: '#6366f1', label: 'Historique' }, { key: valueCol || columns[1] || columns[0], type: 'line', color: '#f59e0b', label: 'Prévision', dashed: true }], forecastFrom: rawData.length };
  return [{ json: { formattedResponse: `## 📈 ${title || 'Tendance & Prévision'}\n${description ? `*${description}*\n` : ''}*${rawData.length} périodes analysées — 3 périodes prévisionnelles*`, sessionId, format: 'prediction', resultCount: rawData.length, rawResults: chartData, forecast, metadata: { ...metadata, chart_config: forecastChart, forecast_periods: 3, forecast_start: rawData.length } } }];
}
if (formatType === 'table') {
  const cols = columns.length ? columns : Object.keys(rawData[0] || {});
  const badge = table_config?.badge_column || null;
  const header = '| ' + cols.join(' | ') + ' |';
  const sep = '|' + cols.map(() => ' --- ').join('|') + '|';
  const rows = rawData.map(r => '| ' + cols.map(c => { let val = fmt(r[c]); if (badge && c === badge) { const color = table_config?.badge_colors?.[val] || 'gray'; const emoji = {red:'🔴',orange:'🟠',yellow:'🟡',green:'🟢',gray:'⚪'}[color] || '⚪'; val = `${emoji} ${val}`; } return val; }).join(' | ') + ' |').join('\n');
  return [{ json: { formattedResponse: `## 📊 ${title || 'Résultats'}\n${description ? `*${description}*\n` : ''}\n${header}\n${sep}\n${rows}\n\n*${resultCount} résultat(s)*`, sessionId, format: 'table', resultCount, rawResults: rawData, metadata } }];
}
if (formatType === 'stats') {
  const icons = kpi_config?.icons || ['📊','💰','📈','👥','📦','⚡'];
  const labels = kpi_config?.labels || columns;
  const prefixes = kpi_config?.prefix || [];
  let statsCards = [];
  if (rawData.length === 1) {
    statsCards = Object.entries(rawData[0]).map(([col, val], idx) => ({ label: labels[idx] || col, value: val, prefix: prefixes[idx] || '', icon: icons[idx % icons.length], stat_details: stats?.[col] || null }));
  } else {
    statsCards = rawData.map((row, idx) => { const firstKey = Object.keys(row)[0]; const valueKey = Object.keys(row).find(k => !isNaN(parseFloat(row[k])) && k !== firstKey) || firstKey; return { label: String(row[firstKey] || `Item ${idx+1}`), value: row[valueKey], prefix: '', icon: icons[idx % icons.length] }; });
  }
  return [{ json: { formattedResponse: `## ${title || 'Statistiques clés'}${description ? `\n*${description}*` : ''}`, sessionId, format: 'stats', resultCount, rawResults: statsCards, metadata } }];
}
if (formatType === 'list') {
  let response = title ? `## ${title}\n` : '';
  rawData.forEach((row, i) => { const vals = columns.length ? columns : Object.keys(row); if (vals.length === 1) response += `• **${fmt(row[vals[0]])}**\n`; else response += `${i+1}. **${fmt(row[vals[0]])}** — ${vals.slice(1).map(k => fmt(row[k])).join(' · ')}\n`; });
  response += `\n*${resultCount} résultat(s)*`;
  return [{ json: { formattedResponse: response, sessionId, format: 'list', resultCount, rawResults: rawData, metadata } }];
}
if (formatType === 'simple') {
  const [[col, val]] = Object.entries(rawData[0] || {});
  return [{ json: { formattedResponse: `**${title || col} :** ${fmt(val)}`, sessionId, format: 'stats', resultCount: 1, rawResults: [{ label: title || col, value: val }], metadata } }];
}
const titleLine = title ? `## ${title}\n` : '';
return [{ json: { formattedResponse: titleLine + mdTable(rawData.slice(0, 30)) + `\n\n*${resultCount} résultat(s)*`, sessionId, format: 'table', resultCount, rawResults: rawData, metadata } }];

const error = $('SaaS GESTOCKPRO2').first().json.error;
const userQuestion = $('Webhook2').first().json.body.message;
const sessionId = $('Webhook2').first().json.body.sessionId;
let icon = '❌', title = 'Erreur de requête', message = "Une erreur est survenue lors de l'exécution de la requête.", hint = 'Reformulez votre question différemment.';
const errMsg = (error?.message || error?.toString() || '').toLowerCase();
const rawErr = error?.message || '';

// ── Extraction de la colonne/table fautive ────────────────────────────
const colMatch = rawErr.match(/column ["']?([\w.]+)["']? does not exist/i);
const relMatch = rawErr.match(/relation ["']?([\w.]+)["']? does not exist/i);
const badCol = colMatch ? colMatch[1] : null;
const badRel = relMatch ? relMatch[1] : null;

if (badCol) {
  icon = '🔍'; title = 'Colonne inconnue';
  message = `La colonne **${badCol}** n'existe pas dans la base de données.`;
  hint = `Reformulez votre question. La donnée "${badCol}" n'est peut-être pas disponible dans votre schéma.`;
} else if (badRel) {
  icon = '🗂️'; title = 'Table introuvable';
  message = `La table **${badRel}** n'existe pas.`;
  hint = 'Vérifiez que la fonctionnalité est activée dans votre abonnement.';
} else if (errMsg.includes('syntax error') || errMsg.includes('parse error')) {
  icon = '⚠️'; title = 'Erreur de syntaxe SQL';
  message = 'La requête générée contient une erreur de syntaxe.';
  hint = 'Reformulez votre question de façon plus précise.';
} else if (errMsg.includes('does not exist') || errMsg.includes('relation')) {
  icon = '🔍'; title = 'Élément introuvable';
  message = "Une table ou colonne demandée n'existe pas dans votre base.";
  hint = 'Vérifiez que la fonctionnalité est disponible dans votre plan.';
} else if (errMsg.includes('tenant_id') || errMsg.includes('permission') || errMsg.includes('access denied')) {
  icon = '🔒'; title = 'Accès refusé';
  message = "Vous n'avez pas les autorisations nécessaires pour cette requête.";
  hint = 'Vérifiez votre abonnement ou contactez votre administrateur.';
} else if (errMsg.includes('timeout') || errMsg.includes('connection') || errMsg.includes('econnrefused')) {
  icon = '🌐'; title = 'Problème de connexion';
  message = 'La connexion à la base de données a expiré ou été refusée.';
  hint = 'Réessayez dans quelques instants.';
} else if (errMsg.includes('ambiguous')) {
  icon = '🔀'; title = 'Requête ambiguë';
  message = 'La requête référence une colonne présente dans plusieurs tables.';
  hint = 'Reformulez en précisant la table (ex: "les ventes du mois").';
} else if (errMsg.includes('division by zero') || errMsg.includes('divide by zero')) {
  icon = '➗'; title = 'Division par zéro';
  message = 'Le calcul demandé génère une division par zéro.';
  hint = 'Il n\'y a probablement pas de données pour cette période.';
}

return [{ json: { formattedResponse: `${icon} **${title}**\n\n${message}\n\n💡 *${hint}*`, sessionId, format: 'error', resultCount: 0, status: 'ERROR' } }];

// ============================================================
// GENERATE DOCUMENT — Multi-templates selon le type demandé
// Types supportés :
//   FACTURE/PROFORMA  → DocumentPreview React natif
//   BON DE LIVRAISON  → DocumentPreview React natif  
//   RAPPORT           → HTML riche (iframe)
//   FICHE DE PAIE     → HTML riche (iframe)
//   FICHE EMPLOYÉ     → HTML riche (iframe)
//   BON DE COMMANDE   → HTML riche (iframe)
// ============================================================
const allResults = $input.all();
const sessionId = $('Webhook2').first().json.body.sessionId;

if (!allResults.length) {
  return [{ json: {
    formattedResponse: 'Aucune donnée trouvée pour générer ce document.',
    format: 'general', resultCount: 0, sessionId
  }}];
}

const aiOutput = $('Parse AI Output').first().json;
const docType  = (aiOutput.document_type || aiOutput.format || 'document_report').toLowerCase();
const docTitle = aiOutput.title || 'Document';

// ── Branding tenant ───────────────────────────────────────────────────────
let tenant = {};
try { tenant = $('Merge Tenant Branding').first().json.tenant || {}; } catch(e) {}

const companyName   = tenant.company_name   || 'Mon Entreprise';
const logoUrl       = tenant.logo_url       || '';
const cachetUrl     = tenant.cachet_url     || '';
const primaryColor  = tenant.primary_color  || '#6366f1';
const accentColor   = tenant.secondary_color|| '#22d3ee';
const address       = tenant.address        || '';
const phone         = tenant.phone          || '';
const email         = tenant.email          || '';
const taxRate       = parseFloat(tenant.tax_rate) || 18;
const currency      = tenant.currency       || 'FCFA';
const footerMention = tenant.footer_mention || 'Merci pour votre confiance.';
const invoicePrefix = tenant.invoice_prefix || 'FAC';
const fontFamily    = tenant.font_family    || 'Segoe UI';

// ── Données SQL ───────────────────────────────────────────────────────────
const rawData = allResults.map(item => {
  const { _metadata, ...rest } = item.json || {};
  return rest;
});
const inv = rawData[0] || {};

// ── Helpers ───────────────────────────────────────────────────────────────
const fmt = (v, isCurr = false) => {
  if (v === null || v === undefined) return '—';
  if (typeof v === 'string' && /^\d{4}-\d{2}-\d{2}/.test(v))
    return new Date(v).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' });
  const n = parseFloat(v);
  if (!isNaN(n)) {
    const s = n.toLocaleString('fr-FR', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
    return isCurr ? `${s} ${currency}` : s;
  }
  return String(v);
};

const today  = new Date().toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' });
const ym = new Date().toLocaleDateString('fr-FR', { year: '2-digit', month: '2-digit' }).replace('/', '');
const refNum = `${invoicePrefix}-${ym}-${Math.floor(Math.random() * 9000 + 1000)}`;

// ── Classification du type de document ───────────────────────────────────
const isInvoice   = ['invoice','proforma','document_invoice','document_proforma','facture','facture_proforma'].some(t => docType.includes(t));
const isDelivery  = ['delivery','bon_livraison','bon_sortie','document_delivery'].some(t => docType.includes(t));
const isPayslip   = ['payslip','fiche_paie','fiche_salaire','paie','payroll','document_payslip'].some(t => docType.includes(t));
const isEmployee  = ['employee','employe','fiche_employe','fiche_employé','personnel','document_employee'].some(t => docType.includes(t));
const isOrder     = ['order','commande','bon_commande','purchase','document_order'].some(t => docType.includes(t));
const isReceipt   = ['receipt','recu','reçu','quittance','document_receipt'].some(t => docType.includes(t));
const isReport    = !isInvoice && !isDelivery && !isPayslip && !isEmployee && !isOrder && !isReceipt;
const isProforma  = docType.includes('proforma');
const isBonSortie = isDelivery;

// ── Logo block ────────────────────────────────────────────────────────────
const logoBlock = logoUrl
  ? `<img src="${logoUrl}" alt="${companyName}" style="height:52px;object-fit:contain;border-radius:6px;">`
  : `<div style="display:inline-flex;align-items:center;gap:8px;">
       <div style="width:40px;height:40px;background:${primaryColor};border-radius:10px;display:flex;align-items:center;justify-content:center;color:white;font-size:16px;font-weight:900;">${companyName.slice(0,2).toUpperCase()}</div>
       <span style="font-size:18px;font-weight:900;color:#0f172a;">${companyName}</span>
     </div>`;

const emetteurInfo = [address, phone, email].filter(Boolean).join(' · ');

// ── CSS commun ────────────────────────────────────────────────────────────
const CSS = `
  :root { --primary: ${primaryColor}; --accent: ${accentColor}; }
  * { box-sizing: border-box; margin: 0; padding: 0; }

  /* ── Corps — centré, largeur contrainte ───────────────────────────────── */
  html, body { width: 210mm; max-width: 210mm; overflow-x: hidden; }
  body {
    font-family: '${fontFamily}', 'Segoe UI', Arial, sans-serif;
    background: #f1f5f9;
    padding: 20px 0;
    color: #1e293b;
    margin: 0 auto;
  }

  /* ── Page A4 — largeur fixe, débordement masqué ──────────────────────── */
  .page {
    width: 210mm;
    max-width: 210mm;
    min-height: 297mm;
    background: white;
    margin: 0 auto;
    padding: 36px 44px;
    display: flex;
    flex-direction: column;
    overflow: hidden;           /* clip tout débordement */
    box-shadow: 0 4px 32px rgba(0,0,0,0.10);
    border: 1px solid #e2e8f0;
  }

  /* ── Éléments enfants qui ne doivent jamais dépasser la page ─────────── */
  .page img         { max-width: 100%; height: auto; }
