  .totals-box .total-final { background: #0f172a; color: white; border-radius: 14px; padding: 11px 14px; display: flex; justify-content: space-between; align-items: center; margin-top: 8px; gap: 8px; }
  .totals-box .total-final .lbl { font-size: 9px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.1em; white-space: nowrap; }
