  .kpi-card { background: linear-gradient(135deg, #f8fafc, #eef2ff); border: 1px solid #e2e8f0; border-radius: 12px; padding: 14px; text-align: center; overflow: hidden; }
  .kpi-value { font-size: 20px; font-weight: 900; color: var(--primary); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .kpi-label { font-size: 8px; font-weight: 700; color: #64748b; text-transform: uppercase; letter-spacing: 0.08em; margin-top: 4px; }

