  .footer-note { font-size: 8.5px; color: #cbd5e1; font-weight: 700; text-transform: uppercase; line-height: 1.8; font-style: italic; overflow: hidden; word-break: break-word; }
  .cachet-zone { text-align: center; width: 160px; flex-shrink: 0; }
