// ═════════════════════════════════════════════════════════════════════════
// TEMPLATES HTML par type de document
// ═════════════════════════════════════════════════════════════════════════

let bodyHtml = '';

// ─── Multi-page engine ────────────────────────────────────────────────────────
// Nombre max de lignes de tableau avant de créer une nouvelle page
const ROWS_PER_PAGE = 28;
const chunkArray = (arr, n) => { const c=[]; for(let i=0;i<arr.length;i+=n) c.push(arr.slice(i,i+n)); return c.length?c:[[]]; };

/**
 * Génère le HTML multi-pages à partir d'un tableau de chunks de lignes.
 * - Page 1 : header complet (logo, infos entreprise, titre document)
 * - Pages 2+ : header compact (titre + Page X/N)
 * - Toutes : footer avec Page X/N
 * @param {Array}    chunks      - Tableau de tableaux de lignes
 * @param {string}   theadHtml   - HTML du <thead> commun à toutes les pages
 * @param {Function} rowFn       - (row, idx) => '<tr>...</tr>'
 * @param {string}   firstHeader - HTML du header complet pour la page 1
 * @param {string}   kpisHtml    - HTML des KPIs (affiché seulement page 1, avant le tableau)
 * @returns {string} - HTML complet avec .page divs
 */
const buildPaginatedReport = (chunks, theadHtml, rowFn, firstHeader, kpisHtml) => {
  const total = chunks.length;
  return chunks.map((rows, idx) => {
    const pageNum = idx + 1;
    const isFirst = idx === 0;
    const isLast  = idx === total - 1;

    const hdr = isFirst ? firstHeader
      : `<div style="display:flex;justify-content:space-between;align-items:center;padding-bottom:14px;margin-bottom:16px;border-bottom:2px solid #0f172a;">
          <div style="font-size:15px;font-weight:900;color:#0f172a;letter-spacing:-0.5px;">${docTitle.toUpperCase()}</div>
          <div style="display:flex;align-items:center;gap:12px;">
            <span style="font-size:11px;color:#64748b;font-weight:600;">${companyName}</span>
            <span class="doc-ref">Page ${pageNum}/${total}</span>
          </div>
        </div>`;

    const tableSection = `<div class="section">
      ${isFirst ? `<div class="section-title">Données — ${rawData.length} résultat(s)</div>` : ''}
      <table class="items-table">
        ${theadHtml}
        <tbody>${rows.map(rowFn).join('')}</tbody>
      </table>
    </div>`;

    const footer = `<div class="footer" style="margin-top:auto">
      <div class="footer-note">${companyName} · ${today}<br>${footerMention}</div>
      <div style="font-size:11px;font-weight:700;color:#94a3b8;">Page ${pageNum} / ${total}</div>
    </div>`;

    return `<div class="page"${!isLast ? ' style="page-break-after:always;margin-bottom:32px;"' : ''}>
${hdr}
${isFirst && kpisHtml ? kpisHtml : ''}
${tableSection}
${footer}
</div>`;
  }).join('\n');
};

let isMultiPage = false;


// ── 1. FACTURE / PROFORMA ─────────────────────────────────────────────────
if (isInvoice) {
  const status = (inv.status || '').toLowerCase();
  const isPaid = status === 'paid' || status === 'payé' || status === 'completed';
  const getAmt = r => parseFloat(r.total_ttc || r.amount || r.montant || r.total || 0);
  const totalTTC = rawData.reduce((s, r) => s + getAmt(r), 0);
  const totalHT  = totalTTC / (1 + taxRate / 100);
  const totalTVA = totalTTC - totalHT;

  const badge = isPaid
    ? `<span class="badge badge-paid">✓ Payée</span>`
    : `<span class="badge badge-pending">⏳ En attente</span>`;

  const rows = rawData.map((item, i) => {
    const qty  = parseFloat(item.quantity || item.qte || 1);
    const ttc  = getAmt(item);
    const ht   = ttc / (1 + taxRate / 100);
    return `<tr>
      <td><span class="sku">${item.sku || '—'}</span></td>
      <td><div class="item-name">${item.article || item.name || item.produit || item.description || 'Article'}</div></td>
      <td class="center">${qty}</td>
      <td class="right">${fmt(ht / qty)}</td>
      <td class="right">${fmt(ht)} ${currency}</td>
    </tr>`;
  }).join('');

  bodyHtml = `
    <div class="header">
      <div class="header-left">
        ${logoBlock}
        <div class="company-meta">${[address,phone,email].filter(Boolean).join('<br>')}</div>
      </div>
      <div class="header-right">
        <div class="doc-title">${isProforma ? 'FACTURE PROFORMA' : 'FACTURE'}</div>
        <div class="doc-ref">Réf: #${inv.id || inv.reference || refNum}</div>
        <div class="doc-date">Date : ${fmt(inv.invoice_date || inv.sale_date) || today}</div>
        ${inv.due_date ? `<div class="doc-date">Échéance : ${fmt(inv.due_date)}</div>` : ''}
        <div style="margin-top:8px">${badge}</div>
      </div>
    </div>
    <div class="info-grid">
      <div class="info-card">
        <div class="info-card-label">Émetteur</div>
        <div class="info-card-value">${companyName}</div>
        <div class="info-card-detail">${emetteurInfo || '—'}</div>
      </div>
      <div class="info-card">
        <div class="info-card-label">Facturé à</div>
        <div class="info-card-value">${inv.company_name || inv.client || 'Client'}</div>
        <div class="info-card-detail">${[inv.address,inv.phone,inv.email].filter(Boolean).join('<br>') || '—'}</div>
      </div>
    </div>
    <div class="section">
      <div class="section-title">Articles & Prestations</div>
      <table class="items-table">
        <thead><tr><th>Réf.</th><th>Désignation</th><th style="text-align:center">Qté</th><th style="text-align:right">P.U HT</th><th style="text-align:right;border-radius:0 12px 12px 0">Montant HT</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>
    </div>
    <div class="totals-box">
      <div class="row"><span>Sous-total HT</span><span>${fmt(totalHT)} ${currency}</span></div>
      <div class="row"><span>TVA (${taxRate}%)</span><span>${fmt(totalTVA)} ${currency}</span></div>
      <div class="sep"></div>
      <div class="total-final"><span class="lbl">NET À PAYER</span><span class="amt">${fmt(totalTTC)} ${currency}</span></div>
    </div>
    <div class="footer" style="margin-top:24px">
      <div class="footer-note">${companyName} · Kernel Cloud v3.2<br>ID: ${refNum.toUpperCase()}<br>${footerMention}${isProforma ? '<br><em>Document proforma sans valeur comptable</em>' : ''}</div>
      <div class="cachet-zone">
        <div class="cachet-title">VISA & CACHET</div>
        <div class="cachet-box">
          ${isPaid && cachetUrl ? `<img src="${cachetUrl}" style="height:68px;object-fit:contain;mix-blend-mode:multiply;" alt="Cachet">` :
            isPaid ? `<div style="border:3px solid rgba(16,185,129,0.4);color:#10b981;border-radius:50%;padding:8px 14px;transform:rotate(-12deg);font-weight:900;font-size:14px">PAYÉ</div>` : ''}
        </div>
      </div>
    </div>
    ${isProforma ? '<div class="watermark">PROFORMA</div>' : ''}`;

// ── 2. BON DE LIVRAISON ───────────────────────────────────────────────────
} else if (isDelivery) {
  const rows = rawData.map((r, i) => `<tr>
    <td><span class="sku">${r.sku || r.reference || '—'}</span></td>
    <td><div class="item-name">${r.name || r.produit || r.article || r.description || '—'}</div></td>
    <td class="center">${r.quantity || r.qte || '—'}</td>
    <td class="center">${r.quantity || r.qte || '—'}</td>
    <td class="center" style="color:#94a3b8;font-size:13px">☐</td>
  </tr>`).join('');

  bodyHtml = `
    <div class="header">
      <div class="header-left">${logoBlock}<div class="company-meta">${emetteurInfo}</div></div>
      <div class="header-right">
        <div class="doc-title">BON DE LIVRAISON</div>
        <div class="doc-ref">Réf: #${refNum}</div>
        <div class="doc-date">Date : ${today}</div>
        <div class="doc-date">Client : ${inv.company_name || inv.client || '—'}</div>
      </div>
    </div>
    <div class="section">
      <table class="items-table">
        <thead><tr><th>Réf.</th><th>Désignation</th><th style="text-align:center">Qté commandée</th><th style="text-align:center">Qté livrée</th><th style="text-align:center;border-radius:0 12px 12px 0">✓</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>
    </div>
    <div class="sig-row">
      <div class="sig"><div class="sig-line">Signature & cachet émetteur</div></div>
      <div class="sig"><div class="sig-line">Signature récepteur + date</div></div>
    </div>
    <div class="footer" style="margin-top:auto">
      <div class="footer-note">${companyName} · ${footerMention}</div>
      <div class="footer-note">${refNum.toUpperCase()}</div>
    </div>`;

// ── 3. FICHE DE PAIE ──────────────────────────────────────────────────────
} else if (isPayslip) {

  // ─── Helper : calcule et retourne le HTML d'une fiche de paie pour UN employé
  const buildOnePayslipHtml = (emp) => {
    if (emp.contract_check === 'NO_CONTRACT' || (!emp.contract_salary && !emp.base_salary)) return null;

    const baseSalary0   = parseFloat(emp.contract_salary || emp.base_salary || 0);
    const primesMonth0  = parseFloat(emp.primes_mois || 0);
    const deductAvance0 = parseFloat(emp.deduction_avance || 0);
    const joursAbsNP0   = parseFloat(emp.jours_abs_non_payes || 0);
    const salaireJour0  = baseSalary0 / 22;
    const deductAbsence0= Math.round(salaireJour0 * joursAbsNP0);
    const IPRES_RATE0=0.056; const IPRES_CAP0=432000; const CSS_RATE0=0.01; const IPM_RATE0=0.03;
    const ipresBase0    = Math.min(baseSalary0, IPRES_CAP0);
    const ipresEmp0     = Math.round(ipresBase0 * IPRES_RATE0);
    const css0          = Math.round(baseSalary0 * CSS_RATE0);
    const ipm0          = Math.round(baseSalary0 * IPM_RATE0);
    const totalCotis0   = ipresEmp0 + css0 + ipm0;
    const brutImp0      = baseSalary0 + primesMonth0 - totalCotis0;
    let ir0 = 0;
    if      (brutImp0 > 500000) ir0 = Math.round(brutImp0 * 0.40);
    else if (brutImp0 > 250000) ir0 = Math.round(brutImp0 * 0.30);
    else if (brutImp0 > 150000) ir0 = Math.round(brutImp0 * 0.20);
    else if (brutImp0 > 100000) ir0 = Math.round(brutImp0 * 0.15);
    else if (brutImp0 > 75000)  ir0 = Math.round(brutImp0 * 0.12);
    else if (brutImp0 > 50000)  ir0 = Math.round(brutImp0 * 0.10);
    const totalRet0   = totalCotis0 + ir0 + deductAvance0 + deductAbsence0;
    const netSalary0  = baseSalary0 + primesMonth0 - totalRet0;
    const month0      = emp.payroll_month || emp.mois || new Date().toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });
    const cLabel0     = emp.contract_type && emp.contract_type !== 'AUCUN' ? emp.contract_type : 'CDI';
    const cStart0     = emp.contract_start ? fmt(emp.contract_start) : (emp.hire_date ? fmt(emp.hire_date) : '—');
    const empName0    = [emp.first_name, emp.last_name].filter(Boolean).join(' ') || '—';

    const empBodyHtml = `
    <div class="header">
      <div class="header-left">${logoBlock}<div class="company-meta">${emetteurInfo}</div></div>
      <div class="header-right">
        <div class="doc-title">FICHE DE PAIE</div>
        <div class="doc-ref">${month0.toString().toUpperCase()}</div>
        <div class="doc-date">Émise le : ${today}</div>
      </div>
    </div>
    <div class="info-grid">
      <div class="info-card">
        <div class="info-card-label">Employé</div>
        <div class="info-card-value">${empName0}</div>
        <div class="info-card-detail">
          ${emp.position ? `Poste : ${emp.position}<br>` : ''}
          ${emp.department ? `Département : ${emp.department}<br>` : ''}
          ${emp.hire_date ? `Embauché le : ${fmt(emp.hire_date)}` : ''}
        </div>
      </div>
      <div class="info-card">
        <div class="info-card-label">Contrat</div>
        <div class="info-card-value">${cLabel0}</div>
        <div class="info-card-detail">
          ${emp.email ? `✉ ${emp.email}<br>` : ''}
          Début contrat : ${cStart0}<br>
          ${emp.status ? `Statut : <strong>${emp.status}</strong>` : ''}
        </div>
      </div>
    </div>
    <div class="section">
      <div class="section-title">Détail de la rémunération</div>
      <table class="items-table">
        <thead><tr><th>Rubrique</th><th>Type</th><th style="text-align:right;border-radius:0 12px 12px 0">Montant</th></tr></thead>
        <tbody>
          <tr><td class="item-name">Salaire de base (contrat)</td><td><span class="badge badge-info">Gain</span></td><td class="right">${fmt(baseSalary0, true)}</td></tr>
          ${primesMonth0 > 0 ? `<tr><td class="item-name">Primes & Indemnités du mois</td><td><span class="badge badge-info">Gain</span></td><td class="right">${fmt(primesMonth0, true)}</td></tr>` : ''}
          <tr><td class="item-name" style="color:#64748b">Brut imposable</td><td><span class="badge badge-neutral">Référence</span></td><td class="right" style="color:#64748b">${fmt(brutImp0, true)}</td></tr>
          ${ipresEmp0>0?`<tr><td class="item-name">IPRES (5,6% ≤ 432 000)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(ipresEmp0,true)}</td></tr>`:''}
          ${css0>0?`<tr><td class="item-name">CSS (1%)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(css0,true)}</td></tr>`:''}
          ${ipm0>0?`<tr><td class="item-name">IPM / Assurance maladie (3%)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(ipm0,true)}</td></tr>`:''}
          ${ir0>0?`<tr><td class="item-name">IRPP (impôt sur le revenu)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(ir0,true)}</td></tr>`:''}
          ${deductAvance0>0?`<tr><td class="item-name">Remboursement avance sur salaire</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(deductAvance0,true)}</td></tr>`:''}
          ${deductAbsence0>0?`<tr><td class="item-name">Absence non rémunérée (${joursAbsNP0} j)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(deductAbsence0,true)}</td></tr>`:''}
        </tbody>
      </table>
      <div class="totals-box">
        <div class="row"><span>Total gains</span><span>${fmt(baseSalary0+primesMonth0,true)}</span></div>
        <div class="row" style="color:#dc2626"><span>Total retenues</span><span>- ${fmt(totalRet0,true)}</span></div>
        <div class="sep"></div>
        <div class="total-final"><span class="lbl">NET À PAYER</span><span class="amt">${fmt(netSalary0)} ${currency}</span></div>
      </div>
    </div>
    <div class="sig-row" style="margin-top:28px">
      ${cachetUrl ? `<div class="sig"><img src="${cachetUrl}" style="height:80px;object-fit:contain;opacity:0.85;"><div class="sig-line">Cachet & Signature employeur</div></div>` : `<div class="sig"><div class="sig-line">Signature employeur</div></div>`}
      <div class="sig"><div class="sig-line">Signature & accusé de réception</div></div>
    </div>
    <div class="footer" style="margin-top:auto">
      <div class="footer-note">${companyName} · Fiche de paie confidentielle · ${today}</div>
      <div class="footer-note">${refNum.toUpperCase()}</div>
    </div>`;

    return `<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><title>Fiche de paie — ${empName0}</title><style>${CSS}</style></head><body><div class="page">${empBodyHtml}</div></body></html>`;
  };

  // ─── Génération en masse : plusieurs employés ──────────────────────────
  if (rawData.length > 1) {
    const validEmps = rawData.filter(e => e.contract_check !== 'NO_CONTRACT' && (e.contract_salary || e.base_salary));
    if (!validEmps.length) {
      return [{ json: {
        formattedResponse: `❌ Aucun des ${rawData.length} employés trouvés n'a de contrat actif avec salaire.`,
        format: 'general', resultCount: 0, sessionId
      }}];
    }
    const documents = validEmps.map(emp => {
      const ym2 = new Date().toLocaleDateString('fr-FR', { year: '2-digit', month: '2-digit' }).replace('/', '');
      return {
        html: buildOnePayslipHtml(emp),
        title: `Fiche de paie — ${[emp.first_name, emp.last_name].filter(Boolean).join(' ')}`,
        filename: `paie_${(emp.last_name||'employe').replace(/[^a-z0-9]/gi,'_')}_${ym2}.html`,
      };
    });
    const skipped = rawData.length - validEmps.length;
    const skipNote = skipped > 0 ? ` (${skipped} ignoré${skipped>1?'s':''} — pas de contrat actif)` : '';
    return [{ json: {
      formattedResponse: `📄 **${documents.length} fiche${documents.length>1?'s':''} de paie** générée${documents.length>1?'s':''} avec succès${skipNote}.`,
      format: 'document_html',
      resultCount: documents.length,
      isMultiDoc: true,
      documentArray: documents,
      documentCount: documents.length,
      createZip: documents.length > 5,
      sessionId,
      metadata: {
        format: 'document_html',
        title: `${documents.length} fiches de paie`,
        isMultiDoc: true,
        createZip: documents.length > 5,
      }
    }}];
  }

  // ─── Fiche de paie unique (code original) ─────────────────────────────
  const emp = inv;

  // ── Blocage : pas de contrat actif ─────────────────────────────────────
  if (emp.contract_check === 'NO_CONTRACT' || (!emp.contract_salary && !emp.base_salary)) {
    return [{ json: {
      formattedResponse: `❌ Impossible de générer la fiche de paie de **${[emp.first_name, emp.last_name].filter(Boolean).join(' ') || 'cet employé'}** : aucun contrat actif trouvé.\n\nVeuillez d'abord créer un contrat actif (CDI, CDD, STAGE...) avec un salaire pour cet employé dans le module RH → Contrats.`,
      format: 'general',
      resultCount: 0,
      sessionId
    }}];
  }

  const baseSalary      = parseFloat(emp.contract_salary || emp.base_salary || 0);
  const primesMonth     = parseFloat(emp.primes_mois || 0);
  const deductAvance    = parseFloat(emp.deduction_avance || 0);
  const joursAbsNP      = parseFloat(emp.jours_abs_non_payes || 0);

  // Déduction absence non payée (salaire journalier = salaire / 22 jours ouvrés)
  const salaireJour     = baseSalary / 22;
  const deductAbsence   = Math.round(salaireJour * joursAbsNP);

  // Calculs cotisations sociales (barème OHADA/Sénégal)
  const IPRES_RATE = 0.056;   // 5.6% employé
  const IPRES_CAP  = 432000;  // plafond mensuel IPRES
  const CSS_RATE   = 0.01;    // 1% CSS
  const IPM_RATE   = 0.03;    // 3% IPM/assurance maladie

  const ipresBase  = Math.min(baseSalary, IPRES_CAP);
  const ipresEmp   = Math.round(ipresBase * IPRES_RATE);
  const css        = Math.round(baseSalary * CSS_RATE);
  const ipm        = Math.round(baseSalary * IPM_RATE);
  const totalCotisations = ipresEmp + css + ipm;

  // IR progressif (IRPP simplifié Sénégal)
  const brutImposable = baseSalary + primesMonth - totalCotisations;
  let ir = 0;
  if      (brutImposable > 600000) ir = Math.round(brutImposable * 0.30);
  else if (brutImposable > 400000) ir = Math.round(brutImposable * 0.25);
  else if (brutImposable > 200000) ir = Math.round(brutImposable * 0.20);
  else if (brutImposable > 100000) ir = Math.round(brutImposable * 0.15);
  else if (brutImposable > 50000)  ir = Math.round(brutImposable * 0.10);

  const totalRetenues  = totalCotisations + ir + deductAvance + deductAbsence;
  const netSalary      = baseSalary + primesMonth - totalRetenues;
  const month          = emp.payroll_month || emp.mois || new Date().toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });
  const contractLabel  = emp.contract_type && emp.contract_type !== 'AUCUN' ? emp.contract_type : 'CDI';
  const contractStart  = emp.contract_start ? fmt(emp.contract_start) : (emp.hire_date ? fmt(emp.hire_date) : '—');

  bodyHtml = `
    <div class="header">
      <div class="header-left">${logoBlock}<div class="company-meta">${emetteurInfo}</div></div>
      <div class="header-right">
        <div class="doc-title">FICHE DE PAIE</div>
        <div class="doc-ref">${month.toString().toUpperCase()}</div>
        <div class="doc-date">Émise le : ${today}</div>
      </div>
    </div>
    <div class="info-grid">
      <div class="info-card">
        <div class="info-card-label">Employé</div>
        <div class="info-card-value">${[emp.first_name, emp.last_name].filter(Boolean).join(' ') || '—'}</div>
        <div class="info-card-detail">
          ${emp.position ? `Poste : ${emp.position}<br>` : ''}
          ${emp.department ? `Département : ${emp.department}<br>` : ''}
          ${emp.hire_date ? `Embauché le : ${fmt(emp.hire_date)}` : ''}
        </div>
      </div>
      <div class="info-card">
        <div class="info-card-label">Contrat</div>
        <div class="info-card-value">${contractLabel}</div>
        <div class="info-card-detail">
          ${emp.email ? `✉ ${emp.email}<br>` : ''}
          Début contrat : ${contractStart}<br>
          ${emp.status ? `Statut : <strong>${emp.status}</strong>` : ''}
        </div>
      </div>
    </div>
    <div class="section">
      <div class="section-title">Détail de la rémunération</div>
      <table class="items-table">
        <thead><tr><th>Rubrique</th><th>Type</th><th style="text-align:right;border-radius:0 12px 12px 0">Montant</th></tr></thead>
        <tbody>
          <tr><td class="item-name">Salaire de base (contrat)</td><td><span class="badge badge-info">Gain</span></td><td class="right">${fmt(baseSalary, true)}</td></tr>
          ${primesMonth > 0 ? `<tr><td class="item-name">Primes & Indemnités du mois</td><td><span class="badge badge-info">Gain</span></td><td class="right">${fmt(primesMonth, true)}</td></tr>` : ''}
          <tr><td class="item-name" style="color:#64748b">Brut imposable</td><td><span class="badge badge-neutral">Référence</span></td><td class="right" style="color:#64748b">${fmt(brutImposable, true)}</td></tr>
          ${ipresEmp > 0 ? `<tr><td class="item-name">IPRES (5,6% ≤ 432 000)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(ipresEmp, true)}</td></tr>` : ''}
          ${css > 0 ? `<tr><td class="item-name">CSS (1%)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(css, true)}</td></tr>` : ''}
          ${ipm > 0 ? `<tr><td class="item-name">IPM / Assurance maladie (3%)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(ipm, true)}</td></tr>` : ''}
          ${ir > 0 ? `<tr><td class="item-name">IRPP (impôt sur le revenu)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(ir, true)}</td></tr>` : ''}
          ${deductAvance > 0 ? `<tr><td class="item-name">Remboursement avance sur salaire</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(deductAvance, true)}</td></tr>` : ''}
          ${deductAbsence > 0 ? `<tr><td class="item-name">Absence non rémunérée (${joursAbsNP} j × ${fmt(salaireJour)} ${currency}/j)</td><td><span class="badge badge-warn">Retenue</span></td><td class="right" style="color:#dc2626">- ${fmt(deductAbsence, true)}</td></tr>` : ''}
        </tbody>
      </table>
      <div class="totals-box">
        <div class="row"><span>Total gains</span><span>${fmt(baseSalary + primesMonth, true)}</span></div>
        <div class="row" style="color:#dc2626"><span>Total retenues</span><span>- ${fmt(totalRetenues, true)}</span></div>
        <div class="sep"></div>
        <div class="total-final"><span class="lbl">NET À PAYER</span><span class="amt">${fmt(netSalary)} ${currency}</span></div>
      </div>
    </div>
    <div class="sig-row" style="margin-top:28px">
      ${cachetUrl ? `<div class="sig"><img src="${cachetUrl}" style="height:80px;object-fit:contain;opacity:0.85;"><div class="sig-line">Cachet & Signature employeur</div></div>` : `<div class="sig"><div class="sig-line">Signature employeur</div></div>`}
      <div class="sig"><div class="sig-line">Signature & accusé de réception</div></div>
    </div>
    <div class="footer" style="margin-top:auto">
      <div class="footer-note">${companyName} · Fiche de paie confidentielle · ${today}</div>
      <div class="footer-note">${refNum.toUpperCase()}</div>
    </div>`;

// ── 4. FICHE EMPLOYÉ ──────────────────────────────────────────────────────
} else if (isEmployee) {
  const emp = inv;
  const cols = Object.keys(rawData[0] || {});
  const employeeRows = rawData.map((emp, i) => `
    <tr>
      <td class="item-name">${[emp.first_name, emp.last_name, emp.nom, emp.prenom, emp.name].filter(Boolean).join(' ') || '—'}</td>
      <td>${emp.position || emp.poste || '—'}</td>
