        <div class="info-card-detail">
          ${emp.email ? `✉ ${emp.email}<br>` : ''}
          ${emp.hire_date ? `Embauché le : ${fmt(emp.hire_date)}<br>` : ''}
          ${emp.status ? `Statut : <strong>${emp.status}</strong>` : ''}
        </div>
      </div>
      <div class="info-card">
        <div class="info-card-label">Poste & Département</div>
        <div class="info-card-value">${emp.position || emp.poste || '—'}</div>
        <div class="info-card-detail">
          ${emp.department || emp.departement ? `Département : ${emp.department || emp.departement}<br>` : ''}
          ${emp.base_salary || emp.salary ? `Salaire : ${fmt(parseFloat(emp.base_salary || emp.salary), true)}` : ''}
        </div>
      </div>
    </div>` : `
    <div class="section">
      <div class="section-title">Liste des employés — ${rawData.length} résultat(s)</div>
      <table class="items-table">
        <thead><tr><th>Nom complet</th><th>Poste</th><th>Département</th><th>Email</th><th>Statut</th><th style="text-align:right;border-radius:0 12px 12px 0">Salaire</th></tr></thead>
        <tbody>${employeeRows}</tbody>
      </table>
    </div>`}
    <div class="footer" style="margin-top:auto">
      <div class="footer-note">${companyName} · Document RH confidentiel · ${today}</div>
      <div class="cachet-zone">
        <div class="cachet-title">VISA DRH</div>
        <div class="cachet-box">${cachetUrl ? `<img src="${cachetUrl}" style="height:60px;object-fit:contain;mix-blend-mode:multiply;">` : ''}</div>
      </div>
    </div>`;

// ── 5. BON DE COMMANDE ────────────────────────────────────────────────────
} else if (isOrder) {
  const getAmt = r => parseFloat(r.total_ttc || r.amount || r.montant || r.price || r.prix || 0);
  const totalTTC = rawData.reduce((s, r) => s + getAmt(r), 0);
  const rows = rawData.map((item, i) => `<tr>
    <td><span class="sku">${item.sku || item.reference || '—'}</span></td>
    <td><div class="item-name">${item.name || item.produit || item.article || item.description || 'Article'}</div></td>
    <td class="center">${item.quantity || item.qte || 1}</td>
    <td class="right">${fmt(parseFloat(item.unit_price || item.prix_unitaire || item.unit_price || getAmt(item) / (parseFloat(item.quantity||1))))}</td>
    <td class="right">${fmt(getAmt(item))} ${currency}</td>
  </tr>`).join('');

  bodyHtml = `
    <div class="header">
      <div class="header-left">${logoBlock}<div class="company-meta">${emetteurInfo}</div></div>
