    phone:       inv.phone   || '',
    email:       inv.email   || '',
  },
  items: rawData.map(r => ({
    name:       r.article || r.name || r.produit || r.description || 'Article',
    stock_item: { name: r.article || r.name || r.produit || 'Article', sku: r.sku || '' },
    quantity:   parseFloat(r.quantity || r.qte || 1),
    unitPrice:  parseFloat(r.prix_unitaire || r.unit_price || 0),
    totalTtc:   parseFloat(r.total_ttc || r.amount || 0),
    discount:   parseFloat(r.discount || 0),
  }))
} : null;

const tenantData = reactDocType ? {
  name:          companyName,
  address:       address,
  phone:         phone,
  email:         email,
  logoUrl:       logoUrl,
  cachetUrl:     cachetUrl,
  invoiceFooter: footerMention,
} : null;

const documentData = reactDocType ? {
  type:     reactDocType,
  sale:     saleData,
  tenant:   tenantData,
  currency: currency,
} : null;

return [{
  json: {
    formattedResponse: `📄 **${docTitle}** généré avec succès.`,
    format:        'document_html',
    resultCount:   rawData.length,
    rawResults:    rawData,
    documentHtml:  html,
    documentType:  docType,
    documentTitle: docTitle,
    refNumber:     refNum,
    sessionId,
    documentData,
    metadata: {
      format:        'document_html',
      title:         docTitle,
      document_type: docType,
      ref:           refNum,
      company_name:  companyName,
      generated_at:  new Date().toISOString(),
      documentData,
    }
  }
}];
